import React, { useState, useEffect } from 'react';
import { Link } from 'react-router-dom';
import axios from 'axios';
import styled from 'styled-components';
import { FaPlus, FaArrowLeft, FaEdit, FaTrash, FaUser, FaCalendarAlt } from 'react-icons/fa';
import { format, parseISO } from 'date-fns';

const Container = styled.div`
  min-height: 100vh;
  padding: 20px;
`;

const Header = styled.header`
  display: flex;
  justify-content: space-between;
  align-items: center;
  margin-bottom: 30px;
`;

const Title = styled.h1`
  color: white;
`;

const BackBtn = styled(Link)`
  color: white;
  display: flex;
  align-items: center;
  gap: 8px;
  background: rgba(255, 255, 255, 0.2);
  padding: 10px 20px;
  border-radius: 10px;
`;

const AddBtn = styled.button`
  background: rgba(255, 255, 255, 0.2);
  color: white;
  padding: 10px 20px;
  border-radius: 10px;
  display: flex;
  align-items: center;
  gap: 8px;
`;

const TaskList = styled.div`
  display: flex;
  flex-direction: column;
  gap: 15px;
`;

const TaskCard = styled.div`
  background: white;
  padding: 20px;
  border-radius: 15px;
  box-shadow: 0 10px 30px rgba(0, 0, 0, 0.1);
  display: flex;
  justify-content: space-between;
  align-items: center;
`;

const TaskInfo = styled.div`
  flex: 1;
`;

const TaskTitle = styled.h3`
  margin-bottom: 5px;
`;

const TaskMeta = styled.div`
  font-size: 14px;
  color: #666;
  display: flex;
  gap: 20px;
`;

const PriorityBadge = styled.span`
  padding: 5px 10px;
  border-radius: 5px;
  font-size: 12px;
  font-weight: 600;
  background: ${props => {
    if (props.priority === 'High') return '#fee2e2';
    if (props.priority === 'Medium') return '#fef3c7';
    return '#dcfce7';
  }};
  color: ${props => {
    if (props.priority === 'High') return '#dc2626';
    if (props.priority === 'Medium') return '#d97706';
    return '#16a34a';
  }};
`;

const StatusBadge = styled.span`
  padding: 5px 10px;
  border-radius: 5px;
  font-size: 12px;
  font-weight: 600;
  background: ${props => {
    if (props.status === 'Done') return '#dcfce7';
    if (props.status === 'InProgress') return '#dbeafe';
    return '#f3f4f6';
  }};
  color: ${props => {
    if (props.status === 'Done') return '#16a34a';
    if (props.status === 'InProgress') return '#2563eb';
    return '#4b5563';
  }};
`;

const Modal = styled.div`
  position: fixed;
  top: 0;
  left: 0;
  right: 0;
  bottom: 0;
  background: rgba(0, 0, 0, 0.5);
  display: flex;
  align-items: center;
  justify-content: center;
  z-index: 100;
`;

const ModalContent = styled.div`
  background: white;
  padding: 30px;
  border-radius: 15px;
  width: 90%;
  max-width: 500px;
`;

const Input = styled.input`
  width: 100%;
  padding: 12px;
  margin: 10px 0;
  border: 1px solid #ddd;
  border-radius: 8px;
`;

const Select = styled.select`
  width: 100%;
  padding: 12px;
  margin: 10px 0;
  border: 1px solid #ddd;
  border-radius: 8px;
`;

const TextArea = styled.textarea`
  width: 100%;
  padding: 12px;
  margin: 10px 0;
  border: 1px solid #ddd;
  border-radius: 8px;
  min-height: 100px;
`;

const Button = styled.button`
  background: #667eea;
  color: white;
  padding: 10px 20px;
  border-radius: 8px;
  margin-right: 10px;
`;

const Tasks = () => {
  const [tasks, setTasks] = useState([]);
  const [projects, setProjects] = useState([]);
  const [users, setUsers] = useState([]);
  const [showModal, setShowModal] = useState(false);
  const [editingTask, setEditingTask] = useState(null);
  const [newTask, setNewTask] = useState({
    title: '',
    description: '',
    projectId: '',
    assignedTo: '',
    priority: 'Medium',
    dueDate: ''
  });

  useEffect(() => {
    fetchTasks();
    fetchProjects();
  }, []);

  const fetchTasks = async () => {
    try {
      const res = await axios.get('/api/tasks');
      setTasks(res.data);
    } catch (error) {
      console.error('Error fetching tasks:', error);
    }
  };

  const fetchProjects = async () => {
    try {
      const res = await axios.get('/api/projects');
      setProjects(res.data);
    } catch (error) {
      console.error('Error fetching projects:', error);
    }
  };

  const handleCreate = async (e) => {
    e.preventDefault();
    try {
      await axios.post('/api/tasks', newTask);
      setNewTask({
        title: '',
        description: '',
        projectId: '',
        assignedTo: '',
        priority: 'Medium',
        dueDate: ''
      });
      setShowModal(false);
      fetchTasks();
    } catch (error) {
      console.error('Error creating task:', error);
    }
  };

  const handleUpdate = async (e) => {
    e.preventDefault();
    try {
      await axios.put(`/api/tasks/${editingTask._id}`, newTask);
      setNewTask({
        title: '',
        description: '',
        projectId: '',
        assignedTo: '',
        priority: 'Medium',
        dueDate: ''
      });
      setEditingTask(null);
      setShowModal(false);
      fetchTasks();
    } catch (error) {
      console.error('Error updating task:', error);
    }
  };

  const handleDelete = async (taskId) => {
    if (window.confirm('Are you sure you want to delete this task?')) {
      try {
        await axios.delete(`/api/tasks/${taskId}`);
        fetchTasks();
      } catch (error) {
        console.error('Error deleting task:', error);
      }
    }
  };

  const openEdit = (task) => {
    setEditingTask(task);
    setNewTask({
      title: task.title,
      description: task.description || '',
      projectId: task.project._id,
      assignedTo: task.assignedTo?._id || '',
      priority: task.priority,
      dueDate: task.dueDate ? format(parseISO(task.dueDate), 'yyyy-MM-dd') : ''
    });
    setShowModal(true);
  };

  return (
    <Container>
      <Header>
        <div style={{ display: 'flex', gap: '15px', alignItems: 'center' }}>
          <BackBtn to="/">
            <FaArrowLeft />
          </BackBtn>
          <Title>Tasks</Title>
        </div>
        <AddBtn onClick={() => {
          setEditingTask(null);
          setNewTask({
            title: '',
            description: '',
            projectId: '',
            assignedTo: '',
            priority: 'Medium',
            dueDate: ''
          });
          setShowModal(true);
        }}>
          <FaPlus /> New Task
        </AddBtn>
      </Header>

      <TaskList>
        {tasks.map(task => (
          <TaskCard key={task._id}>
            <TaskInfo>
              <TaskTitle>{task.title}</TaskTitle>
              <TaskMeta>
                <span>{task.project?.name}</span>
                <span><FaUser /> {task.assignedTo?.name || 'Unassigned'}</span>
                {task.dueDate && <span><FaCalendarAlt /> {format(parseISO(task.dueDate), 'MMM dd')}</span>}
              </TaskMeta>
            </TaskInfo>
            <div style={{ display: 'flex', gap: '10px', alignItems: 'center' }}>
              <PriorityBadge priority={task.priority}>{task.priority}</PriorityBadge>
              <StatusBadge status={task.status}>{task.status}</StatusBadge>
              <button onClick={() => openEdit(task)} style={{ color: '#667eea' }}>
                <FaEdit />
              </button>
              <button onClick={() => handleDelete(task._id)} style={{ color: '#ef4444' }}>
                <FaTrash />
              </button>
            </div>
          </TaskCard>
        ))}
      </TaskList>

      {showModal && (
        <Modal onClick={() => setShowModal(false)}>
          <ModalContent onClick={e => e.stopPropagation()}>
            <h2>{editingTask ? 'Edit Task' : 'Create Task'}</h2>
            <form onSubmit={editingTask ? handleUpdate : handleCreate}>
              <Input
                placeholder="Title"
                value={newTask.title}
                onChange={e => setNewTask({ ...newTask, title: e.target.value })}
                required
              />
              <TextArea
                placeholder="Description"
                value={newTask.description}
                onChange={e => setNewTask({ ...newTask, description: e.target.value })}
              />
              <Select
                value={newTask.projectId}
                onChange={e => setNewTask({ ...newTask, projectId: e.target.value })}
                required
              >
                <option value="">Select Project</option>
                {projects.map(p => (
                  <option key={p._id} value={p._id}>{p.name}</option>
                ))}
              </Select>
              <Select
                value={newTask.assignedTo}
                onChange={e => setNewTask({ ...newTask, assignedTo: e.target.value })}
              >
                <option value="">Assign to (optional)</option>
                {projects.find(p => p._id === newTask.projectId)?.members.map(m => (
                  <option key={m._id} value={m._id}>{m.name}</option>
                ))}
              </Select>
              <Select
                value={newTask.priority}
                onChange={e => setNewTask({ ...newTask, priority: e.target.value })}
              >
                <option value="Low">Low Priority</option>
                <option value="Medium">Medium Priority</option>
                <option value="High">High Priority</option>
              </Select>
              <Input
                type="date"
                value={newTask.dueDate}
                onChange={e => setNewTask({ ...newTask, dueDate: e.target.value })}
              />
              <div>
                <Button type="submit">{editingTask ? 'Update' : 'Create'}</Button>
                <Button type="button" onClick={() => setShowModal(false)}>Cancel</Button>
              </div>
            </form>
          </ModalContent>
        </Modal>
      )}
    </Container>
  );
};

export default Tasks;
